add_filter( 'rwmb_meta_boxes', '${1:prefix}_register_meta_boxes' );

function ${1:prefix}_register_meta_boxes( \$meta_boxes ) {
    \$meta_boxes[] = [
        'title'      => '${2:Box Title}',
        'id'         => '${3:box-id}',
        'post_types' => [ '${4:post}' ],
        'fields'     => [
            [
                'id'   => '${5:text_field}',
                'name' => '${6:Text Field}',
                'type' => 'text',
            ],
            [
                'id'   => '${7:textarea_field}',
                'name' => '${8:Textarea Field}',
                'type' => 'textarea',
                'rows' => 4,
            ],
            [
                'id'   => '${9:image_field}',
                'name' => '${10:Image}',
                'type' => 'image_advanced',
            ],
        ],
    ];
    return \$meta_boxes;
}
